@import url("https://fonts.googleapis.com/css2?family=DM+Sans:opsz,wght@9..40,400;9..40,700;9..40,900&display=swap");
.app {
  height: calc(var(--appsmith-ui-height) * 1px);
  width: calc(var(--appsmith-ui-width) * 1px);
  justify-content: center;
  border-radius: var(--appsmith-theme-borderRadius);
  box-shadow: var(--appsmith-theme-boxShadow);
  padding: 29px 25px;
  box-sizing: border-box;
  font-family: system-ui;
  background: #fff;
}

.tip-container {
  margin-bottom: 20px;
  font-size: 14px;
  line-height: 1.571429;
}

.tip-container h2 {
  margin-bottom: 20px;
  font-size: 16px;
  font-weight: 700;
}

.tip-header {
  display: flex;
  justify-content: space-between;
  align-items: baseline;
  margin-bottom: 9px;
}

.tip-header div {
  color: #999;
}

.content {
  white-space: pre-wrap;
  word-break: break-word;
  font-size: 14px;
  line-height: 1.571429;
}

.button-container {
  text-align: right;
  padding-top: 4px;
}

.button-container button {
  margin: 0 10px;
  cursor: pointer;
  border-radius: var(--appsmith-theme-borderRadius);
  padding: 6px 16px;
  background: none;
  height: auto;
  transition: all 0.3s ease;
}

.button-container button.primary {
  background: var(--appsmith-theme-primaryColor) !important;
  color: #fff;
  border: 1px solid var(--appsmith-theme-primaryColor) !important;
}

.button-container button.reset {
  border: 1px solid #999;
  color: #999;
  outline: none;
  box-shadow: none;
}

.button-container button.reset:hover:not(:disabled) {
  color: var(--appsmith-theme-primaryColor);
  border-color: var(--appsmith-theme-primaryColor);
}

.button-container button.reset:disabled {
  cursor: default;
}

:root {
  --accent:#6c63ff;
  --green:#58cc02;
  --bg:#f4f7ff;
  --text:#0f172a;
  --muted:#64748b;
  --line:#e6e9f2;
  --shadow:0 18px 50px rgba(15,23,42,.14);
  --shadow-sm:0 8px 18px rgba(15,23,42,.05);
  --bar-bg:rgba(100,116,139,.14);
  --bar-border:rgba(148,163,184,.45);
  --red:#ef4444;
  --amber:#f59e0b;
  --g:#22c55e;
}

* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  font-family: "DM Sans", system-ui, sans-serif;
  background: radial-gradient(1100px 560px at 5% -10%, rgba(88, 204, 2, 0.12), transparent 55%), radial-gradient(900px 520px at 110% 0%, rgba(108, 99, 255, 0.12), transparent 55%), var(--bg);
  color: var(--text);
  min-height: 100vh;
  -webkit-font-smoothing: antialiased;
}

.wrap {
  padding: 16px;
  max-width: 1280px;
  margin: 0 auto;
}

.topbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  padding: 12px 18px;
  flex-wrap: wrap;
  background: rgba(255, 255, 255, 0.82);
  border: 1px solid rgba(230, 233, 242, 0.9);
  border-radius: 24px;
  box-shadow: var(--shadow-sm);
  backdrop-filter: blur(12px);
  margin-bottom: 14px;
}

.brand-title {
  font-weight: 900;
  font-size: 15px;
}

.brand-sub {
  font-size: 12px;
  color: var(--muted);
}

.nav-tabs {
  display: flex;
  gap: 4px;
  padding: 4px;
  border-radius: 999px;
  border: 1px solid rgba(230, 233, 242, 0.9);
  background: #f2f5ff;
}

.nav-tab {
  border: none;
  background: 0 0;
  padding: 8px 14px;
  border-radius: 999px;
  font-weight: 900;
  font-size: 12px;
  font-family: inherit;
  color: var(--muted);
  cursor: pointer;
  transition: all 0.15s;
}

.nav-tab:hover {
  color: var(--text);
}

.nav-tab.active {
  color: var(--text);
  background: #fff;
  box-shadow: 0 8px 16px rgba(15, 23, 42, 0.08);
  border: 1px solid rgba(230, 233, 242, 0.9);
}

.card {
  background: rgba(255, 255, 255, 0.92);
  border: 1px solid rgba(230, 233, 242, 0.9);
  border-radius: 28px;
  box-shadow: var(--shadow);
  padding: 18px;
  margin-bottom: 14px;
}

.dim-nav {
  display: flex;
  gap: 6px;
  flex-wrap: wrap;
  margin-bottom: 14px;
  padding: 6px;
  background: #f2f5ff;
  border-radius: 999px;
  border: 1px solid rgba(230, 233, 242, 0.9);
}

.dim-tab {
  border: none;
  background: 0 0;
  padding: 7px 12px;
  border-radius: 999px;
  font-weight: 900;
  font-size: 11px;
  font-family: inherit;
  color: var(--muted);
  cursor: pointer;
  text-transform: uppercase;
  letter-spacing: 0.3px;
  transition: all 0.15s;
}

.dim-tab.active {
  color: var(--text);
  background: #fff;
  border: 1px solid rgba(230, 233, 242, 0.9);
  box-shadow: 0 4px 12px rgba(15, 23, 42, 0.08);
}

.kpi-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
  gap: 10px;
  margin-top: 10px;
}

.kpi-grid-4 {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
  gap: 10px;
  margin-top: 10px;
}

.kpi {
  background: #fff;
  border: 1px solid rgba(230, 233, 242, 0.9);
  border-radius: 18px;
  padding: 14px;
  box-shadow: var(--shadow-sm);
}

.kpi .k {
  font-size: 12px;
  color: var(--muted);
  font-weight: 800;
  margin-bottom: 4px;
}

.kpi .v {
  font-size: 20px;
  font-weight: 900;
}

.kpi .s {
  font-size: 12px;
  color: var(--muted);
  margin-top: 4px;
}

.bar-card {
  background: #fff;
  border: 1px solid rgba(230, 233, 242, 0.9);
  border-radius: 18px;
  padding: 12px;
  box-shadow: var(--shadow-sm);
  margin-bottom: 8px;
}

.bar-top {
  display: flex;
  justify-content: space-between;
  align-items: baseline;
  gap: 10px;
  margin-bottom: 8px;
}

.bar-name {
  font-weight: 900;
  font-size: 13px;
}

.bar-val {
  font-weight: 900;
  font-size: 13px;
}

.bar-track {
  height: 12px;
  border-radius: 999px;
  background: var(--bar-bg);
  overflow: hidden;
  border: 1px solid var(--bar-border);
}

.bar-track.full {
  border: 2px solid rgba(88, 204, 2, 0.42);
  box-shadow: 0 10px 22px rgba(88, 204, 2, 0.16);
}

.bar-fill {
  height: 100%;
  border-radius: 999px;
  background: linear-gradient(90deg, var(--green), var(--accent));
  transition: width 0.4s;
}

.bar-hint {
  font-size: 12px;
  color: var(--muted);
  margin-top: 6px;
}

.pace-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: 10px;
  margin-top: 10px;
}

.pace-card {
  background: #fff;
  border: 1px solid rgba(230, 233, 242, 0.9);
  border-radius: 18px;
  padding: 14px;
  box-shadow: var(--shadow-sm);
}

.pace-label {
  font-size: 12px;
  color: var(--muted);
  font-weight: 900;
  margin-bottom: 6px;
}

.pace-main {
  font-size: 22px;
  font-weight: 900;
}

.pace-sub {
  font-size: 12px;
  color: var(--muted);
  margin-top: 4px;
}

.signal {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 6px 10px;
  border-radius: 999px;
  font-size: 11px;
  font-weight: 900;
  border: 1px solid;
  white-space: nowrap;
}

.signal.on_track {
  color: #0f5132;
  background: rgba(34, 197, 94, 0.1);
  border-color: rgba(34, 197, 94, 0.3);
}

.signal.at_risk {
  color: #92400e;
  background: rgba(245, 158, 11, 0.1);
  border-color: rgba(245, 158, 11, 0.3);
}

.signal.behind {
  color: #991b1b;
  background: rgba(239, 68, 68, 0.1);
  border-color: rgba(239, 68, 68, 0.3);
}

.funnel-stage {
  display: grid;
  grid-template-columns: 120px 1fr 70px;
  gap: 10px;
  align-items: center;
  margin-bottom: 4px;
}

.funnel-stage .fn {
  font-size: 12px;
  font-weight: 900;
  color: var(--muted);
  text-align: right;
}

.funnel-stage .fb {
  height: 22px;
  border-radius: 11px;
  background: var(--bar-bg);
  overflow: hidden;
  border: 1px solid var(--bar-border);
}

.funnel-stage .fb > div {
  height: 100%;
  border-radius: 11px;
  background: linear-gradient(90deg, var(--green), var(--accent));
  transition: width 0.4s;
}

.funnel-stage .fv {
  font-size: 13px;
  font-weight: 900;
}

.funnel-conv {
  display: grid;
  grid-template-columns: 120px 1fr;
  gap: 10px;
  align-items: center;
  padding: 2px 0;
}

.funnel-conv .ar {
  font-size: 11px;
  color: var(--muted);
  text-align: right;
  font-weight: 900;
}

.funnel-conv .rt {
  font-size: 11px;
  font-weight: 900;
  color: var(--accent);
  padding-left: 6px;
}

.lever-card {
  background: #fff;
  border: 1px solid rgba(230, 233, 242, 0.9);
  border-radius: 18px;
  padding: 14px;
  box-shadow: var(--shadow-sm);
  margin-bottom: 8px;
}

.lever-header {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-bottom: 6px;
}

.lever-prio {
  display: inline-flex;
  padding: 4px 8px;
  border-radius: 999px;
  font-size: 10px;
  font-weight: 900;
  text-transform: uppercase;
  border: 1px solid;
}

.lever-prio.critical {
  color: #991b1b;
  background: rgba(239, 68, 68, 0.1);
  border-color: rgba(239, 68, 68, 0.3);
}

.lever-prio.high {
  color: #92400e;
  background: rgba(245, 158, 11, 0.1);
  border-color: rgba(245, 158, 11, 0.3);
}

.lever-prio.medium {
  color: #1e40af;
  background: rgba(59, 130, 246, 0.1);
  border-color: rgba(59, 130, 246, 0.3);
}

.lever-dim {
  font-size: 11px;
  color: var(--muted);
  font-weight: 900;
  text-transform: uppercase;
  letter-spacing: 0.3px;
}

.lever-title {
  font-weight: 900;
  font-size: 14px;
  margin-bottom: 4px;
}

.lever-detail {
  font-size: 12px;
  color: var(--muted);
  line-height: 1.5;
}

.lever-impact {
  font-size: 12px;
  font-weight: 900;
  color: var(--g);
  margin-top: 6px;
}

.drill-wrap {
  overflow-x: auto;
  margin-top: 10px;
}

.drill-table {
  width: 100%;
  border-collapse: separate;
  border-spacing: 0 6px;
  min-width: 900px;
}

.drill-table th {
  text-align: left;
  font-size: 10px;
  color: var(--muted);
  font-weight: 900;
  padding: 0 8px;
  white-space: nowrap;
  position: sticky;
  top: 0;
  background: #fff;
  z-index: 2;
}

.drill-table th.r {
  text-align: right;
}

.drill-table td {
  background: #fff;
  border: 1px solid rgba(230, 233, 242, 0.9);
  padding: 10px 8px;
  border-left: none;
  border-right: none;
  font-size: 12px;
  vertical-align: middle;
}

.drill-table tr td:first-child {
  border-left: 1px solid rgba(230, 233, 242, 0.9);
  border-top-left-radius: 14px;
  border-bottom-left-radius: 14px;
}

.drill-table tr td:last-child {
  border-right: 1px solid rgba(230, 233, 242, 0.9);
  border-top-right-radius: 14px;
  border-bottom-right-radius: 14px;
}

.drill-table tr:hover td {
  background: #f5f7ff;
}

td.r {
  text-align: right;
}

.badge {
  display: inline-flex;
  padding: 4px 8px;
  border-radius: 999px;
  font-size: 11px;
  font-weight: 900;
  border: 1px solid rgba(230, 233, 242, 0.9);
  background: #f5f7ff;
}

.filter-row {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(160px, 1fr));
  gap: 10px;
  margin-bottom: 12px;
}

.filter-row label {
  display: block;
  font-size: 12px;
  color: var(--muted);
  font-weight: 700;
  margin-bottom: 4px;
}

.filter-row select, .filter-row input {
  width: 100%;
  padding: 10px 12px;
  border: 1px solid rgba(230, 233, 242, 0.9);
  border-radius: 14px;
  outline: none;
  background: #f6f8ff;
  font-size: 13px;
  font-family: inherit;
}

.filter-row select:focus, .filter-row input:focus {
  border-color: rgba(88, 204, 2, 0.45);
  box-shadow: 0 0 0 4px rgba(88, 204, 2, 0.15);
  background: #fff;
}

.btn-primary {
  cursor: pointer;
  padding: 10px 18px;
  border: none;
  border-radius: 14px;
  font-weight: 900;
  font-size: 13px;
  font-family: inherit;
  background: linear-gradient(135deg, var(--green), var(--accent));
  color: #fff;
  box-shadow: 0 14px 26px rgba(88, 204, 2, 0.18);
}

.btn-primary:hover {
  filter: brightness(1.04);
}

.btn-primary:active {
  transform: translateY(1px);
}

.section-title {
  font-size: 15px;
  font-weight: 900;
  margin-bottom: 4px;
}

.section-sub {
  font-size: 12px;
  color: var(--muted);
  margin-bottom: 10px;
}

.msg-box {
  padding: 10px 14px;
  border-radius: 14px;
  font-weight: 900;
  font-size: 13px;
  margin-bottom: 10px;
}

.msg-box.error {
  border: 1px solid rgba(239, 68, 68, 0.22);
  background: rgba(239, 68, 68, 0.08);
  color: #8a1f1f;
}

.msg-box.success {
  border: 1px solid rgba(34, 197, 94, 0.22);
  background: rgba(34, 197, 94, 0.1);
  color: #0f5132;
}

.msg-box.info {
  border: 1px solid rgba(59, 130, 246, 0.22);
  background: rgba(59, 130, 246, 0.08);
  color: #1e3a5f;
}

.chart-container {
  position: relative;
  height: 280px;
  margin-bottom: 20px;
}

.foot {
  margin-top: 14px;
  font-size: 11px;
  color: var(--muted);
  line-height: 1.4;
}

.hidden {
  display: none !important;
}

.dim-panel {
  display: none;
}

.dim-panel.active {
  display: block;
}

@media (max-width: 600px) {
  .topbar {
    flex-direction: column;
  }
  .nav-tabs {
    width: 100%;
    justify-content: center;
  }
  .funnel-stage {
    grid-template-columns: 80px 1fr 50px;
  }
}

