.drill-table th{text-align:left;font-size:10px;color:var(--muted);font-weight:900;padding:0 8px;white-space:nowrap;position:sticky;top:0;background:#fff;z-index:2}
.drill-table th.r{text-align:right}
.drill-table td{background:#fff;border:1px solid rgba(230,233,242,.9);padding:10px 8px;border-left:none;border-right:none;font-size:12px;vertical-align:middle}
.drill-table tr td:first-child{border-left:1px solid rgba(230,233,242,.9);border-top-left-radius:14px;border-bottom-left-radius:14px}
.drill-table tr td:last-child{border-right:1px solid rgba(230,233,242,.9);border-top-right-radius:14px;border-bottom-right-radius:14px}
.drill-table tr:hover td{background:#f5f7ff}td.r{text-align:right}
.badge{display:inline-flex;padding:4px 8px;border-radius:999px;font-size:11px;font-weight:900;border:1px solid rgba(230,233,242,.9);background:#f5f7ff}
.filter-row{display:grid;grid-template-columns:repeat(auto-fit,minmax(160px,1fr));gap:10px;margin-bottom:12px}
.filter-row label{display:block;font-size:12px;color:var(--muted);font-weight:700;margin-bottom:4px}
.filter-row select,.filter-row input{width:100%;padding:10px 12px;border:1px solid rgba(230,233,242,.9);border-radius:14px;outline:none;background:#f6f8ff;font-size:13px;font-family:inherit}
.filter-row select:focus,.filter-row input:focus{border-color:rgba(88,204,2,.45);box-shadow:0 0 0 4px rgba(88,204,2,.15);background:#fff}
.btn-primary{cursor:pointer;padding:10px 18px;border:none;border-radius:14px;font-weight:900;font-size:13px;font-family:inherit;background:linear-gradient(135deg,var(--green),var(--accent));color:#fff;box-shadow:0 14px 26px rgba(88,204,2,.18)}
.btn-primary:hover{filter:brightness(1.04)}.btn-primary:active{transform:translateY(1px)}
.section-title{font-size:15px;font-weight:900;margin-bottom:4px}.section-sub{font-size:12px;color:var(--muted);margin-bottom:10px}
.msg-box{padding:10px 14px;border-radius:14px;font-weight:900;font-size:13px;margin-bottom:10px}
.msg-box.error{border:1px solid rgba(239,68,68,.22);background:rgba(239,68,68,.08);color:#8a1f1f}
.msg-box.success{border:1px solid rgba(34,197,94,.22);background:rgba(34,197,94,.10);color:#0f5132}
.msg-box.info{border:1px solid rgba(59,130,246,.22);background:rgba(59,130,246,.08);color:#1e3a5f}
.chart-container{position:relative;height:280px;margin-bottom:20px}.foot{margin-top:14px;font-size:11px;color:var(--muted);line-height:1.4}
.hidden{display:none!important}.dim-panel{display:none}.dim-panel.active{display:block}
@media(max-width:600px){.topbar{flex-direction:column}.nav-tabs{width:100%;justify-content:center}.funnel-stage{grid-template-columns:80px 1fr 50px}}

